public interface Interface1 {
    void method1();
}

public interface Interface2 {
    void method2();
}

public class MyClass implements Interface1, Interface2 {
    // Interface1の抽象メソッドを実装
    public void method1() {
        System.out.println("Method 1");
    }
    // Interface2の抽象メソッドを実装
    public void method2() {
        System.out.println("Method 2");
    }
}

public interface Interface1 {
    default void method1() {
        System.out.println("Interface1's method1");
    }
}

public class MyClass implements Interface1 {
    // Interface1のデフォルトメソッドをオーバーライド
    public void method1() {
        System.out.println("MyClass's method1");
    }
}

public interface Interface2 {
    void method2();
}

public interface Interface1 extends Interface2 {
    void method1();
}

public interface Interface1 {
    void method2(); // 抽象メソッド

    default void method1() { // デフォルトメソッド
        System.out.println("Default Method1");
    }
}

public interface Interface1 {
    default void method() {
        System.out.println("Interface1's method");
    }
}

public interface Interface2 {
    default void method() {
        System.out.println("Interface2's method");
    }
}

public class MyClass implements Interface1, Interface2 {
    // 同名のデフォルトメソッドの競合を解決するためにメソッドをオーバーライド
    public void method() {
        Interface1.super.method();
    }
}

public interface MyInterface {
    static void staticMethod() {
        System.out.println("Static method in interface");
    }
}

public class MyClass {
    public static void main(String[] args) {
        MyInterface.staticMethod(); // インターフェース名を使用して静的メソッドを呼び出す
    }
}

public interface MyInterface {
    default void defaultMethod1() {
        privateMethod();
    }

    default void defaultMethod2() {
        privateMethod();
    }

    private void privateMethod() {
        System.out.println("Private method in interface");
    }
}

public interface MyInterface {
    // 抽象メソッド
    void abstractMethod();

    // デフォルトメソッド
    default void defaultMethod() {
        System.out.println("Default method in interface");
    }
}

public class MyClass implements MyInterface {
    public void abstractMethod() {
        System.out.println("Abstract method implemented in MyClass");
    }

    public static void main(String[] args) {
        MyClass myClass = new MyClass();
        myClass.abstractMethod(); // Abstract method implemented in MyClass
        myClass.defaultMethod(); // Default method in interface
    }
}

public interface MyInterface {
    void myMethod();
}

public abstract class MyAbstractClass {
    abstract void myMethod();
    void anotherMethod() {
        System.out.println("Method in abstract class");
    }
}

public interface Interface1 {
    default void myMethod() {
        System.out.println("Method in Interface1");
    }
}

public interface Interface2 {
    default void myMethod() {
        System.out.println("Method in Interface2");
    }
}

public class MyClass implements Interface1, Interface2 {
    public void myMethod() {
        Interface1.super.myMethod();
    }

    public static void main(String[] args) {
        MyClass myClass = new MyClass();
        myClass.myMethod(); // Method in Interface1
    }
}
